class Solution:
    def findTheLongestSubstring(self, s: str) -> int:
        n = len(s)
        res = 0
        for i in range(n):
            v = [0] * 5
            for j in range(i, n):
                if s[j] in 'aeiou':
                    v[ord(s[j]) - ord('a')] += 1
                if all(x % 2 == 0 for x in v):
                    res = max(res, j - i + 1)
        return res
